import{_ as t,o as a,c as o,ag as n}from"./chunks/framework.C9sp7nFj.js";const p=JSON.parse('{"title":"Channels Overview","description":"","frontmatter":{},"headers":[],"relativePath":"channels/index.md","filePath":"channels/index.md","lastUpdated":1776579425000}'),i={name:"channels/index.md"};function r(s,e,l,c,h,g){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="channels-overview" tabindex="-1">Channels Overview <a class="header-anchor" href="#channels-overview" aria-label="Permalink to &quot;Channels Overview&quot;">​</a></h1><p>Channels are the gateways that connect your Memoh Bots to the outside world. By configuring channels, you can interact with your bots via your favorite messaging platforms.</p><p>Memoh currently supports the following channels:</p><ul><li><strong><a href="./slack.html">Slack</a></strong>: Workspace messaging with Socket Mode, threads, files, and reactions.</li><li><strong><a href="./telegram.html">Telegram</a></strong>: Feature-rich integration with streaming and attachment support.</li><li><strong><a href="./feishu.html">Feishu (Lark)</a></strong>: Enterprise-ready integration for business workflows.</li><li><strong><a href="./discord.html">Discord</a></strong>: Community-focused integration for servers and direct messages.</li><li><strong><a href="./qq.html">QQ</a></strong>: Quick setup for personal DM bots via the dedicated AI bot registration portal.</li><li><strong><a href="./matrix.html">Matrix</a></strong>: Decentralized messaging protocol support for any Matrix homeserver.</li><li><strong><a href="./misskey.html">Misskey</a></strong>: Federated social/chat style integration with replies and reactions.</li><li><strong><a href="./dingtalk.html">DingTalk</a></strong>: Enterprise chat integration for private and group conversations.</li><li><strong><a href="./wecom.html">WeCom (WeWork)</a></strong>: Enterprise messaging integration for WeCom workspaces.</li><li><strong><a href="./weixin.html">WeChat</a></strong>: Personal messaging via QR login.</li><li><strong><a href="./wechatoa.html">WeChat Official Account</a></strong>: Official account webhook integration for private message scenarios.</li><li><strong>Email</strong>: Connect via SMTP providers, Mailgun, or Gmail OAuth (configured through Email Providers).</li><li><strong>Web</strong>: Built-in chat interface for immediate access.</li></ul><h3 id="wechat-vs-wechat-official-account" tabindex="-1">WeChat vs WeChat Official Account <a class="header-anchor" href="#wechat-vs-wechat-official-account" aria-label="Permalink to &quot;WeChat vs WeChat Official Account&quot;">​</a></h3><p>Memoh supports two different WeChat-related adapters:</p><ul><li><strong>WeChat (<code>weixin</code>)</strong> is the personal-account style integration that relies on QR login.</li><li><strong>WeChat Official Account (<code>wechatoa</code>)</strong> is the official-account / webhook style integration that uses <code>App ID</code>, <code>App Secret</code>, <code>Token</code>, and optional AES settings.</li></ul><p>Choose the one that matches your actual WeChat deployment model.</p><h2 id="general-setup-flow" tabindex="-1">General Setup Flow <a class="header-anchor" href="#general-setup-flow" aria-label="Permalink to &quot;General Setup Flow&quot;">​</a></h2><ol><li><strong>Create an external app/bot</strong>: Register your bot on the target platform.</li><li><strong>Obtain credentials</strong>: Fetch API tokens, App IDs, app secrets, or access tokens.</li><li><strong>Configure in Memoh</strong>: Add the channel from your bot&#39;s <strong>Platforms</strong> tab.</li><li><strong>Save and enable</strong>: Activate the channel to start receiving and sending messages.</li></ol><p>Depending on the platform, the final step may involve:</p><ul><li>copying a webhook callback URL into the platform console</li><li>approving a QR login on mobile</li><li>leaving a long-lived stream/WebSocket connection running through Memoh</li></ul><p>Choose a channel from the sidebar to see detailed configuration guides for each platform.</p>',13)])])}const f=t(i,[["render",r]]);export{p as __pageData,f as default};
